const raw = $input.first().json.message.content;
let parsed;
try {
  parsed = JSON.parse(raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim());
} catch(e) {
  throw new Error('JSON inválido de OpenAI: ' + raw.substring(0,200));
}
const b = $('🎯 Webhook Trigger').first().json.body;
return [{ json: {
  instagram:       parsed.instagram || null,
  facebook:        parsed.facebook  || null,
  image_prompt:    parsed.instagram?.image_prompt || '',
  platforms:       b.platforms,
  topic:           b.topic,
  type:            b.type,
  angle:           b.angle || null,
  image_model:     b.image_model || 'flux',
  fal_model_id:    b.fal_model_id || 'fal-ai/flux-pro/v1.1',
  has_own_image:   b.has_own_image || false,
  image_url:       b.image_url || null,
  has_text_in_image: b.has_text_in_image || false,
  approval_number: b.approval_number,
  timestamp:       b.timestamp
}}];

